#!/usr/bin/env node

/**
 * AIMock Recording Script — step-05-score
 *
 * Records a golden run of the test-skill step-05 scoring step.
 * Requires ANTHROPIC_API_KEY in the environment.
 *
 * Usage: npm run test:aimock:record
 */

const path = require('node:path');
const fs = require('node:fs/promises');
const { LLMock } = require('@copilotkit/aimock');
const { buildStepContext, executeStep } = require('./harness');

const FIXTURE_DIR = path.join(__dirname, 'fixtures', 'step05-score');
const PROJECT_ROOT = path.join(__dirname, '..', '..');

async function main() {
  // Validate API key
  if (!process.env.ANTHROPIC_API_KEY) {
    console.error('Error: ANTHROPIC_API_KEY environment variable is required for recording.');
    console.error('Set it and re-run: ANTHROPIC_API_KEY=sk-ant-... npm run test:aimock:record');
    process.exit(1);
  }

  console.log('AIMock Recording — step-05-score');
  console.log('================================\n');

  // Clean previous fixtures
  const existingFiles = await fs.readdir(FIXTURE_DIR);
  for (const file of existingFiles) {
    if (file.endsWith('.json')) {
      await fs.unlink(path.join(FIXTURE_DIR, file));
    }
  }
  console.log('Cleaned previous fixtures.\n');

  // Start AIMock in record mode
  const mock = new LLMock({ port: 0 }); // Random available port
  await mock.start();

  mock.enableRecording({
    providers: {
      anthropic: 'https://api.anthropic.com',
    },
    fixturePath: FIXTURE_DIR,
  });

  const baseUrl = mock.url;
  console.log(`AIMock started at ${baseUrl} (recording mode)\n`);

  try {
    // Load known-good scoring data from existing contract fixtures
    const contractPath = path.join(PROJECT_ROOT, 'test', 'fixtures', 'compute-score-contract.json');
    const contractData = JSON.parse(await fs.readFile(contractPath, 'utf8'));
    const testCase = contractData[0]; // suite_a_all_active

    // Build a mock test report that step-05 would read
    const mockTestReport = buildMockTestReport(testCase.input);

    // Build the scoring rules content
    const scoringRulesPath = path.join(PROJECT_ROOT, 'src', 'skf-test-skill', 'references', 'scoring-rules.md');
    const scoringRules = await fs.readFile(scoringRulesPath, 'utf8');

    // Build step context
    const stepFilePath = path.join(PROJECT_ROOT, 'src', 'skf-test-skill', 'steps-c', 'step-05-score.md');
    const { system, userMessage } = await buildStepContext(
      stepFilePath,
      {
        scoringRulesFile: 'references/scoring-rules.md',
        scoringScript: 'scripts/compute-score.py',
        outputFile: 'test-report-example-skill.md',
        forge_version: 'forge-data/example-skill',
      },
      {
        'references/scoring-rules.md': scoringRules,
        'test-report-example-skill.md': mockTestReport,
      },
    );

    console.log('Sending step-05-score to Claude via AIMock proxy...\n');

    const result = await executeStep(userMessage, system, {
      baseUrl,
      apiKey: process.env.ANTHROPIC_API_KEY,
    });

    console.log('Response received and recorded.\n');
    console.log('--- Response preview (first 500 chars) ---');
    console.log(result.content.slice(0, 500));
    console.log('---\n');

    // List saved fixtures
    const savedFiles = (await fs.readdir(FIXTURE_DIR)).filter((f) => f.endsWith('.json'));
    console.log(`Fixtures saved (${savedFiles.length} file(s)):`);
    for (const file of savedFiles) {
      const stat = await fs.stat(path.join(FIXTURE_DIR, file));
