/**
 * AIMock Replay Test — step-05-score
 *
 * Replays a recorded golden run of the test-skill step-05 scoring step
 * and validates the LLM response structure, script invocation, and
 * end-to-end chain against the actual compute-score.py script.
 *
 * Requires recorded fixtures in test/aimock/fixtures/step05-score/.
 * Run `npm run test:aimock:record` to generate fixtures first.
 *
 * Usage: npm run test:aimock
 */

const path = require('node:path');
const fs = require('node:fs/promises');
const { execSync } = require('node:child_process');
const { LLMock } = require('@copilotkit/aimock');
const { buildStepContext, executeStep, extractJson, validateScoringJson, validateScriptInvocation } = require('./harness');

// ANSI colors (matches project convention)
const C = {
  reset: '\u001B[0m',
  green: '\u001B[32m',
  red: '\u001B[31m',
  yellow: '\u001B[33m',
  cyan: '\u001B[36m',
  dim: '\u001B[2m',
};

let passed = 0;
let failed = 0;

function assert(condition, testName, errorMessage = '') {
  if (condition) {
    console.log(`${C.green}\u2713${C.reset} ${testName}`);
    passed++;
  } else {
    console.log(`${C.red}\u2717${C.reset} ${testName}`);
    if (errorMessage) {
      console.log(`  ${C.dim}${errorMessage}${C.reset}`);
    }
    failed++;
  }
}

const PROJECT_ROOT = path.join(__dirname, '..', '..');
const FIXTURE_DIR = path.join(__dirname, 'fixtures', 'step05-score');

async function runTests() {
  console.log(`${C.cyan}========================================`);
  console.log('AIMock Replay Tests — step-05-score');
  console.log(`========================================${C.reset}\n`);

  // Check fixtures exist
  const fixtureFiles = (await fs.readdir(FIXTURE_DIR)).filter((f) => f.endsWith('.json'));
  if (fixtureFiles.length === 0) {
    console.log(`${C.yellow}No fixtures found in ${FIXTURE_DIR}`);
    console.log(`Run 'npm run test:aimock:record' to generate fixtures first.${C.reset}`);
    console.log(`\n${C.yellow}Skipping AIMock replay tests (no fixtures).${C.reset}`);
    process.exit(0);
  }

  console.log(`${C.dim}Fixtures: ${fixtureFiles.length} file(s) in ${path.relative(PROJECT_ROOT, FIXTURE_DIR)}${C.reset}\n`);

  // Start AIMock in strict replay mode
  const mock = new LLMock({ port: 0, fixturePath: FIXTURE_DIR });
  await mock.start();

  let response;

  try {
    // Build the same context used during recording
    const contractPath = path.join(PROJECT_ROOT, 'test', 'fixtures', 'compute-score-contract.json');
    const contractData = JSON.parse(await fs.readFile(contractPath, 'utf8'));
    const testCase = contractData[0]; // suite_a_all_active

    const mockTestReport = buildMockTestReport(testCase.input);
    const scoringRulesPath = path.join(PROJECT_ROOT, 'src', 'skf-test-skill', 'references', 'scoring-rules.md');
    const scoringRules = await fs.readFile(scoringRulesPath, 'utf8');

    const stepFilePath = path.join(PROJECT_ROOT, 'src', 'skf-test-skill', 'steps-c', 'step-05-score.md');
    const { system, userMessage } = await buildStepContext(
      stepFilePath,
      {
        scoringRulesFile: 'references/scoring-rules.md',
        scoringScript: 'scripts/compute-score.py',
        outputFile: 'test-report-example-skill.md',
        forge_version: 'forge-data/example-skill',
      },
      {
        'references/scoring-rules.md': scoringRules,
        'test-report-example-skill.md': mockTestReport,
      },
    );

    // Execute step against AIMock
    response = await executeStep(userMessage, system, {
      baseUrl: mock.url,
      apiKey: 'mock-key',
    });

    assert(response.content.length > 0, 'AIMock returned a non-empty response');
  } catch (error) {
    console.log(`${C.red}Failed to get response from AIMock: ${error.message}${C.reset}`);
    if (error.message.includes('503')) {
      console.log(`${C.dim}503 = strict mode rejected request (fixture mismatch). Re-record with 'npm run test:aimock:record'.${C.reset}`);
    }
    await mock.stop();
    process.exit(1);
  }

  // ============================================================
  // Suite 1: LLM Constructs Valid Scoring JSON
  // ============================================================
  console.log(`\n${C.yellow}Suite 1: Scoring JSON Construction${C.reset}\n`);

  const json = extractJson(response.content);
  assert(json !== null, 'Response contains extractable JSON');

  if (json) {
    const validation = validateScoringJson(json);
    assert(validation.valid, 'JSON matches compute-score.py input schema', validation.errors.join('; '));

    assert(json.mode === 'contextual', 'mode is "contextual" (matches test case)', `Got: ${json.mode}`);

    assert(json.tier === 'Deep', 'tier is "Deep" (matches test case)', `Got: ${json.tier}`);

    assert(
      json.scores && typeof json.scores.exportCoverage === 'number',
      'scores.exportCoverage is a number',
      `Got: ${json.scores?.exportCoverage} (${typeof json.scores?.exportCoverage})`,
    );
  }

  // ============================================================
  // Suite 2: Script Invocation Correctness
  // ============================================================
  console.log(`\n${C.yellow}Suite 2: Script Invocation${C.reset}\n`);

  const invocation = validateScriptInvocation(response.content, 'compute-score');
  assert(invocation.valid, 'Response includes compute-score.py invocation command', invocation.error || '');

  // Check it references the frontmatter variable or actual script name
  const hasScriptRef =
    response.content.includes('compute-score') || response.content.includes('{scoringScript}');
  assert(hasScriptRef, 'Response references scoring script by name or variable');

  // ============================================================
  // Suite 3: End-to-End Chain
  // ============================================================
  console.log(`\n${C.yellow}Suite 3: End-to-End Chain (LLM JSON -> Python script -> Result)${C.reset}\n`);

  if (json) {
    const scriptPath = path.join(PROJECT_ROOT, 'src', 'skf-test-skill', 'scripts', 'compute-score.py');
    const jsonInput = JSON.stringify(json);

    try {
      const scriptOutput = execSync(`python3 "${scriptPath}" '${jsonInput}'`, {
        encoding: 'utf8',
        timeout: 10_000,
      });

      const result = JSON.parse(scriptOutput);

      assert(result.totalScore !== undefined, 'Python script returned totalScore', `Output: ${scriptOutput.slice(0, 200)}`);

      assert(typeof result.totalScore === 'number', 'totalScore is a number', `Got: ${typeof result.totalScore}`);

      assert(
        result.result === 'PASS' || result.result === 'FAIL',
        'result is PASS or FAIL',
        `Got: ${result.result}`,
      );

      assert(
        Array.isArray(result.activeCategories),
        'activeCategories is an array',
        `Got: ${typeof result.activeCategories}`,
      );

      assert(
        result.weightSum > 99 && result.weightSum < 101,
        'weights sum to ~100',
        `Got: ${result.weightSum}`,
      );

      // Compare with contract expectations
      const contractPath = path.join(PROJECT_ROOT, 'test', 'fixtures', 'compute-score-contract.json');
      const contractData = JSON.parse(await fs.readFile(contractPath, 'utf8'));
      const expected = contractData[0].expected_output;

      assert(
        result.result === expected.result,
        `Result matches contract expectation: ${expected.result}`,
        `Expected ${expected.result}, got ${result.result}`,
      );

      assert(
        Math.abs(result.totalScore - expected.totalScore) < 1,
        `Total score matches contract (expected ~${expected.totalScore})`,
        `Expected ~${expected.totalScore}, got ${result.totalScore}`,
      );
    } catch (error) {
      assert(false, 'compute-score.py executed successfully', error.message);
    }
  } else {
    console.log(`${C.dim}Skipping end-to-end chain (no JSON extracted from response)${C.reset}`);
  }

  // Cleanup
  await mock.stop();

  // Summary
  console.log(`\n${C.cyan}========================================`);
  console.log(`Results: ${C.green}${passed} passed${C.reset}, ${failed > 0 ? C.red : C.dim}${failed} failed${C.reset}`);
  console.log(`${C.cyan}========================================${C.reset}\n`);

  process.exit(failed > 0 ? 1 : 0);
}

function buildMockTestReport(input) {
  const scores = input.scores;
  return `---
testMode: ${input.mode}
skill_name: example-skill
forge_tier: ${input.tier}
---

# Test Report: example-skill

## Coverage Analysis

Export Coverage: ${scores.exportCoverage}%
${scores.signatureAccuracy !== null ? `Signature Accuracy: ${scores.signatureAccuracy}%` : 'Signature Accuracy: N/A (Quick tier)'}
${scores.typeCoverage !== null ? `Type Coverage: ${scores.typeCoverage}%` : 'Type Coverage: N/A (Quick tier)'}

## Coherence Analysis

${scores.coherence !== null ? `Combined Coherence: ${scores.coherence}%` : 'Not scored (naive mode — weight redistributed)'}

## External Validation

${scores.externalValidation !== null ? `External Validation Score: ${scores.externalValidation}%` : 'N/A (neither tool available — weight redistributed)'}
`;
}

runTests().catch((error) => {
  console.error(`${C.red}Test runner failed: ${error.message}${C.reset}`);
  process.exit(1);
});

